const tradicionais=[{ id:'t1', img:'data:image/jpeg;base64,', name:'Brigadeiro', desc:'Recheado com brigadeiro cremoso tradicional, coberto com raspas de chocolate granulado e brigadeiros do sabor do recheio.', prices:{'250g':70,'350g':80}, badge:null },{ id:'t2', img:'data:image/jpeg;base64,', name:'Ninho', desc:'Recheado com brigadeiro cremoso de Ninho, coberto com Ninho, raspas de chocolate branco e brigadeiros do sabor do recheio.', prices:{'250g':70,'350g':80}, badge:null },{ id:'t3', img:'data:image/jpeg;base64,', name:'Beijinho', desc:'Recheado com beijinho cremoso, coberto com coco em flocos, brigadeiros do sabor do recheio para um sabor autêntico e irresistível.', prices:{'250g':70,'350g':80}, badge:null },{ id:'t4', img:'data:image/jpeg;base64,', name:'Doce de Leite', desc:'Recheado com doce de leite cremoso, coberto com doce de leite, pedaços de amendoim e brigadeiro de churros.', prices:{'250g':70,'350g':80}, badge:null }];const especiais=[{ id:'e1', img:'data:image/jpeg;base64,', name:'Surpresa de Morango', desc:'Brigadeiro branco cremoso e geleia artesanal de morango, coberto com morangos frescos e Kit Kat.', prices:{'250g':85,'350g':95}, badge:null },{ id:'e2', img:'data:image/jpeg;base64,', name:'Maracujá com Chocolate', desc:'Brigadeiro de maracujá intercalado com brigadeiro de cacau, coberto com Kit Kat e toque de maracujá.', prices:{'250g':85,'350g':95}, badge:null },{ id:'e3', img:'data:image/jpeg;base64,', name:'Paçoca com Nutella', desc:'Brigadeiro cremoso de paçoca, coberto com Nutella e finalizado com farofa de paçoca crocante.', prices:{'250g':85,'350g':95}, badge:{ text:'Quase esgotado', cls:'badge-scarce' } },{ id:'e4', img:'data:image/jpeg;base64,', name:'Ninho com Nutella', desc:'Brigadeiro cremoso de Ninho, coberto com Nutella e finalizado com pedaços crocantes de Kit Kat.', prices:{'250g':85,'350g':95}, badge:null },{ id:'e5', img:'data:image/jpeg;base64,', name:'Dois Amores', desc:'Brigadeiro branco cremoso e brigadeiro de cacau intenso, coberto com pedaços crocantes de Kit Kat.', prices:{'250g':85,'350g':95}, badge:null },{ id:'e6', img:'data:image/jpeg;base64,', name:'Oreo', desc:'Brigadeiro branco cremoso e pedaços de biscoito Oreo, coberto com Oreo e Chocolate Laka Oreo.', prices:{'250g':85,'350g':95}, badge:null }];const additionalsData=[{id:'a1',name:'Nutella',price:6},{id:'a2',name:"MM's",price:6},{id:'a3',name:'Ouro Branco',price:6},{id:'a4',name:'Kit Kat',price:6},{id:'a5',name:'Morango Fresco',price:6},{id:'a6',name:'Kinder Bueno',price:6},{id:'a7',name:'Brigadeiros',price:6}];let cart=[];let selectedSizes={};let selectedShells={};function selectCardShell(cardId,shell,btn){selectedShells[cardId]=shell;btn.closest('.shell-options').querySelectorAll('.shell-btn').forEach(b=>b.classList.remove('active'));btn.classList.add('active');}function selectSize(id,size){selectedSizes[id]=size;document.querySelectorAll(`.size-btn[data-card="${id}"]`).forEach(b=>{b.classList.toggle('active',b.dataset.size===size);});}function renderCards(products,containerId){const c=document.getElementById(containerId);if(!c)return;c.innerHTML=products.map((p,i)=>{selectedSizes[p.id]='350g';selectedShells[p.id]='Ao leite';const delay=i*80;const addonsHtml=additionalsData.map(a=>`<button class="card-addon-btn" id="cadd-${p.id}-${a.id}" onclick="toggleCardAddon('${p.id}','${a.id}',this)">${a.name}+R$${a.price}</button>`).join('');return `<div class="product-card reveal ${p.badge ? 'featured':''}" style="transition-delay:${delay}ms;">${p.img ? `<div class="product-img-wrap" onclick="openLightbox('${p.img}','${p.name}')"><img class="product-img" src="${p.img}" alt="${p.name}" loading="lazy" style="object-position:center ${p.id==='t3' ? '70%':'50%'};"><div class="product-img-hint">🔍 Toque para ver</div></div>`:''}<div class="product-inner"><div class="product-badge-row">${p.badge ? `<span class="badge ${p.badge.cls}">${p.badge.text}</span>`:''}</div><p class="product-name">${p.name}</p><p class="product-desc">${p.desc}</p></div><div class="size-options"><button class="size-btn" data-card="${p.id}" data-size="250g" onclick="selectSize('${p.id}','250g')"><span class="size-weight">250g</span><span class="size-price">R$ ${p.prices['250g']}</span></button><button class="size-btn best-value active" data-card="${p.id}" data-size="350g" onclick="selectSize('${p.id}','350g')"><span class="size-weight">350g</span><span class="size-price">R$ ${p.prices['350g']}</span></button></div><button class="card-addons-toggle" id="toggle-${p.id}" onclick="toggleAddonsPanel('${p.id}')">✨ Turbine seu ovo<span class="arrow">▼</span></button><div class="card-addons-panel" id="panel-add-${p.id}">${addonsHtml}</div><div class="shell-picker-wrap" style="margin:0 20px 16px;"><p class="shell-picker-label">Tipo de casca</p><div class="shell-options"><button class="shell-btn active" onclick="selectCardShell('${p.id}','Ao leite',this)">Ao leite</button><button class="shell-btn" onclick="selectCardShell('${p.id}','Meio amargo',this)">Meio amargo</button><button class="shell-btn" onclick="selectCardShell('${p.id}','Choc. branco',this)">Choc. branco</button></div></div><button class="add-btn" onclick="addToCart('${p.id}')">+Adicionar ao pedido</button></div>`;}).join('');initReveal();}function renderAdditionals(){const c=document.getElementById('additionals-list');if(!c)return;c.innerHTML=additionalsData.map(a=>`<div class="additional-item" id="add-${a.id}" onclick="toggleAdditional('${a.id}')"><div class="additional-left"><div class="additional-check" id="check-${a.id}">✓</div><span class="additional-name">${a.name}</span></div><span class="additional-price">+R$ ${a.price}</span></div>`).join('');}function toggleAdditional(id){const el=document.getElementById('add-'+id);const wasActive=el.classList.contains('active');el.classList.toggle('active');const a=additionalsData.find(x=>x.id===id);if(!a)return;if(!wasActive){cart.push({id:Date.now(),name:a.name,size:'adicional',shell:'-',price:a.price,type:'adicional',addId:id});updateCartUI();showToast('✓ '+a.name+' adicionado!');}else{cart=cart.filter(x=>x.addId!==id);updateCartUI();}}function toggleAddonsPanel(productId){const panel=document.getElementById('panel-add-'+productId);const toggle=document.getElementById('toggle-'+productId);panel.classList.toggle('open');toggle.classList.toggle('open');}function toggleCardAddon(productId,addonId,btn){btn.classList.toggle('active');}function addToCart(productId){const all=[...tradicionais,...especiais];const p=all.find(x=>x.id===productId);if(!p)return;const size=selectedSizes[productId]||'350g';const ovoId=Date.now();cart.push({id:ovoId,name:p.name,size,shell:selectedShells[productId]||'Ao leite',price:p.prices[size],type:'ovo'});additionalsData.forEach(a=>{const btn=document.getElementById('cadd-'+productId+'-'+a.id);if(btn&&btn.classList.contains('active')){cart.push({id:Date.now()+Math.random(),name:a.name+'('+p.name+')',size:'adicional',shell:'-',price:a.price,type:'adicional',parentId:ovoId});btn.classList.remove('active');}});updateCartUI();showToast('✓ '+p.name+' adicionado!');}function selectKitShell(btn){btn.closest('.kit-options').querySelectorAll('.kit-option').forEach(b=>b.classList.remove('active'));btn.classList.add('active');}function addKit(){const filling=document.querySelector('#kit-filling .kit-option.active')?.textContent||'Brigadeiro Tradicional';const toppingEls=document.querySelectorAll('#kit-topping .kit-option.active');if(toppingEls.length<3){showToast('Escolha 3 coberturas!');return;}const toppings=Array.from(toppingEls).map(e=>e.textContent).join('+');const shell=document.querySelector('#kit-shell .kit-option.active')?.textContent||'Ao leite';cart.push({id:Date.now(),name:'Kit Confeiteiro',size:'100g',shell,price:50,detail:filling+' · '+toppings,type:'kit'});updateCartUI();showToast('✓ Kit Confeiteiro adicionado!');}function removeFromCart(id){const item=cart.find(x=>x.id===id)||cart.find(x=>String(x.id)===String(id));if(item&&item.addId){const el=document.getElementById('add-'+item.addId);if(el)el.classList.remove('active');}cart=cart.filter(x=>x.id!==id&&x.parentId!==id);updateCartUI();renderCartModal();}function updateCartUI(){const count=cart.length;const total=cart.reduce((s,i)=>s+i.price,0);document.getElementById('cart-count-badge').textContent=count;document.getElementById('cart-total-badge').textContent='R$ '+total.toFixed(2).replace('.',',');document.getElementById('sticky-cart').classList.toggle('hidden',count===0);}function openCartModal(){renderCartModal();document.getElementById('cart-modal').classList.add('open');}function closeCartOutside(e){if(e.target===document.getElementById('cart-modal')){document.getElementById('cart-modal').classList.remove('open');}}function renderCartModal(){const list=document.getElementById('cart-items-list');const summary=document.getElementById('cart-summary');const entryBox=document.getElementById('entry-note-box');const actions=document.getElementById('cart-actions');if(cart.length===0){list.innerHTML='<div class="empty-cart"><span class="big">🐰</span><p>Seu pedido está vazio.<br>Adicione um ovo delicioso!</p></div>';summary.style.display='none';entryBox.style.display='none';actions.innerHTML='';return;}list.innerHTML=cart.map(item=>`<div class="cart-item"><div style="flex:1;"><p class="cart-item-name">${item.name}</p><p class="cart-item-detail">${item.type==='adicional' ? 'Adicional':item.type==='mini' ? item.size+' · Casca: '+item.shell:item.size+' · Casca: '+item.shell}${item.detail ? '<br>'+item.detail:''}</p><button class="cart-item-remove" onclick="removeFromCart(${item.id})">Remover</button></div><p class="cart-item-price">R$ ${item.price.toFixed(2).replace('.',',')}</p></div>`).join('');const total=cart.reduce((s,i)=>s+i.price,0);const entry=total*0.5;document.getElementById('subtotal-val').textContent='R$ '+total.toFixed(2).replace('.',',');document.getElementById('total-val').textContent='R$ '+total.toFixed(2).replace('.',',');document.getElementById('entry-val').textContent='R$ '+entry.toFixed(2).replace('.',',');summary.style.display='block';entryBox.style.display='block';const msg=buildMsg();actions.innerHTML=`<a class="whatsapp-btn" href="https://wa.me/5573991489627?text=${encodeURIComponent(buildMsg())}" target="_blank"><svg width="22" height="22" viewBox="0 0 24 24" fill="none"><path fill="#fff" d="M20.52 3.48A11.94 11.94 0 0 0 12 0C5.37 0 0 5.37 0 12c0 2.12.55 4.18 1.6 6L0 24l6.2-1.62A11.98 11.98 0 0 0 12 24c6.63 0 12-5.37 12-12 0-3.2-1.25-6.22-3.48-8.52ZM12 22c-1.85 0-3.66-.5-5.24-1.44l-.38-.22-3.68.96.98-3.59-.25-.4A9.97 9.97 0 0 1 2 12c0-5.51 4.49-10 10-10 2.67 0 5.18 1.04 7.07 2.93A9.95 9.95 0 0 1 22 12c0 5.51-4.49 10-10 10Zm5.48-7.48c-.3-.15-1.77-.87-2.04-.97-.28-.1-.48-.15-.68.15-.2.3-.77.97-.95 1.17-.17.2-.35.22-.65.07-.3-.15-1.27-.47-2.42-1.5-.9-.8-1.5-1.79-1.67-2.09-.18-.3-.02-.46.13-.6.14-.14.3-.35.45-.52.15-.17.2-.3.3-.5.1-.2.05-.37-.02-.52-.07-.15-.68-1.64-.93-2.24-.24-.59-.49-.5-.68-.51h-.58c-.2 0-.52.07-.79.37-.28.3-1.04 1.02-1.04 2.48s1.07 2.88 1.22 3.08c.15.2 2.1 3.2 5.08 4.49.71.31 1.26.49 1.69.62.71.23 1.36.2 1.87.12.57-.09 1.77-.72 2.02-1.42.25-.7.25-1.3.17-1.42-.07-.12-.27-.19-.57-.34Z"/></svg>Finalizar pedido no WhatsApp</a>`;}function buildMsg(){let msg='🐰*Cardápio de Páscoa 2026 – Doceria Gourmet*\n\n*Meu pedido:*\n';cart.forEach((item,i)=>{msg+=`${i+1}. ${item.name}(${item.size})– Casca:${item.shell}`;if(item.detail)msg+=` – ${item.detail}`;msg+=` – R$ ${item.price.toFixed(2).replace('.',',')}\n`;});const total=cart.reduce((s,i)=>s+i.price,0);msg+=`\n💰*Total:R$ ${total.toFixed(2).replace('.',',')}*`;msg+=`\n💳*Entrada(50%):R$ ${(total*0.5).toFixed(2).replace('.',',')}*`;msg+='\n\nAguardo confirmação!🍫';return msg;}function selectKidsSingle(btn){btn.closest('.kit-options').querySelectorAll('.kit-option').forEach(b=>b.classList.remove('active'));btn.classList.add('active');}function selectKidsTopping(btn){const active=btn.closest('.kit-options').querySelectorAll('.kit-option.active');if(btn.classList.contains('active')){btn.classList.remove('active');}else if(active.length<2){btn.classList.add('active');}else{showToast('Máximo 2 coberturas!');}}function addKids(){const filling=document.querySelector('#kids-filling .kit-option.active')?.textContent||'Brigadeiro Tradicional';const toppings=Array.from(document.querySelectorAll('#kids-topping .kit-option.active')).map(e=>e.textContent).join('+')||'Sem cobertura';cart.push({id:Date.now(),name:'Ovo Kids',size:'250g',shell:'Choc. branco c/Disquete',price:65,detail:filling+' · '+toppings,type:'kit'});updateCartUI();showToast('✓ Ovo Kids adicionado!');}function selectKitSingle(btn){btn.closest('.kit-options').querySelectorAll('.kit-option').forEach(b=>b.classList.remove('active'));btn.classList.add('active');}function selectKitTopping(btn){const active=btn.closest('.kit-options').querySelectorAll('.kit-option.active');if(btn.classList.contains('active')){btn.classList.remove('active');}else if(active.length<3){btn.classList.add('active');}else{showToast('Máximo 3 coberturas!');}}function showTab(tab,btn){document.querySelectorAll('.tab-panel').forEach(p=>p.classList.remove('active'));document.querySelectorAll('.tab').forEach(b=>b.classList.remove('active'));document.getElementById('panel-'+tab).classList.add('active');btn.classList.add('active');document.querySelector('.urgency-bar').scrollIntoView({behavior:'smooth',block:'start'});setTimeout(initReveal,50);}function showToast(msg){const t=document.getElementById('toast');t.textContent=msg;t.classList.add('show');setTimeout(()=>t.classList.remove('show'),2400);}function initReveal(){const els=document.querySelectorAll('.reveal,.reveal-left,.reveal-right');const obs=new IntersectionObserver((entries)=>{entries.forEach(e=>{if(e.isIntersecting){e.target.classList.add('visible');obs.unobserve(e.target);}});},{threshold:0.1});els.forEach(el=>obs.observe(el));}function updateCountdown(){const easter=new Date('2026-04-05T00:00:00');const diff=easter-new Date();if(diff<=0)return;const d=Math.floor(diff/86400000);const h=Math.floor((diff%86400000)/3600000);const m=Math.floor((diff%3600000)/60000);const s=Math.floor((diff%60000)/1000);document.getElementById('cd-dias').textContent=String(d).padStart(2,'0');document.getElementById('cd-horas').textContent=String(h).padStart(2,'0');document.getElementById('cd-min').textContent=String(m).padStart(2,'0');document.getElementById('cd-seg').textContent=String(s).padStart(2,'0');}renderCards(tradicionais,'tradicionais-cards');renderCards(especiais,'especiais-cards');renderAdditionals();updateCountdown();setInterval(updateCountdown,1000);setTimeout(initReveal,100);function openLightbox(src,name){document.getElementById('lightbox-img').src=src;document.getElementById('lightbox-name').textContent=name;document.getElementById('lightbox').classList.add('open');document.body.style.overflow='hidden';}function closeLightbox(){document.getElementById('lightbox').classList.remove('open');document.body.style.overflow='';}const miniOptions={'mini-a':{name:'2 Mini Ovos 50g',price:25,minQty:10,qtyId:'mini-a-qty',unit:'pares'},'mini-b':{name:'2 Mini Ovos 100g',price:60,minQty:10,qtyId:'mini-b-qty',unit:'pares'},'mini-c':{name:'1 Mini Ovo 100g',price:30,minQty:5,qtyId:'mini-c-qty',unit:'unidades'},'mini-d':{name:'1 Mini Ovo 150g',price:45,minQty:5,qtyId:'mini-d-qty',unit:'unidades'}};

let selectedMini=null;
let miniFlavorCounts={};

var flavorShellIdMap={'Brigadeiro':'Brigadeiro','Ninho':'Ninho','Beijinho':'Beijinho','Doce de Leite':'Doce-de-Leite','Surpresa de Morango':'Surpresa-de-Morango','Maracujá com Chocolate':'Maracuja-com-Chocolate','Paçoca com Nutella':'Pacoca-com-Nutella','Ninho com Nutella':'Ninho-com-Nutella','Dois Amores':'Dois-Amores','Oreo':'Oreo'};
function selectMiniShell(flavor,shell,btn){
  if(!miniFlavorCounts[flavor])miniFlavorCounts[flavor]={qty:0,shell:'Ao leite'};
  miniFlavorCounts[flavor].shell=shell;
  var safeId=flavorShellIdMap[flavor]||flavor;
  ['l','a','b'].forEach(function(s){
    var el=document.getElementById('mfs-'+safeId+'-'+s);
    if(el){el.style.background='transparent';el.style.borderColor='rgba(255,255,255,0.25)';el.style.color='rgba(255,255,255,0.7)';}
  });
  btn.style.background='var(--brown)';btn.style.borderColor='rgba(255,255,255,0.35)';btn.style.color='#fff';
}
var flavorIdMap={'Brigadeiro':'mfq-Brigadeiro','Ninho':'mfq-Ninho','Beijinho':'mfq-Beijinho','Doce de Leite':'mfq-Doce-de-Leite','Surpresa de Morango':'mfq-Surpresa-de-Morango','Maracujá com Chocolate':'mfq-Maracuja-com-Chocolate','Paçoca com Nutella':'mfq-Pacoca-com-Nutella','Ninho com Nutella':'mfq-Ninho-com-Nutella','Dois Amores':'mfq-Dois-Amores','Oreo':'mfq-Oreo'};
var allFlavorIds=['mfq-Brigadeiro','mfq-Ninho','mfq-Beijinho','mfq-Doce-de-Leite','mfq-Surpresa-de-Morango','mfq-Maracuja-com-Chocolate','mfq-Pacoca-com-Nutella','mfq-Ninho-com-Nutella','mfq-Dois-Amores','mfq-Oreo'];

function getMiniTotalQty(){
  if(!selectedMini)return 0;
  return parseInt(document.getElementById(miniOptions[selectedMini].qtyId).textContent);
}
function getMiniFlavorTotal(){
  return Object.values(miniFlavorCounts).reduce(function(a,b){return a+(b.qty||0);},0);
}
function updateFlavorProgress(){
  var total=getMiniTotalQty();
  var chosen=getMiniFlavorTotal();
  var el=document.getElementById('mini-flavor-progress');
  if(el)el.textContent=chosen+' de '+total+' sabores escolhidos';
}
function changeMiniFlavorQty(flavor,delta){
  var total=getMiniTotalQty();
  var current=miniFlavorCounts[flavor]?miniFlavorCounts[flavor].qty:0;
  var newVal=current+delta;
  if(newVal<0)return;
  if(delta>0&&getMiniFlavorTotal()>=total){showToast('Limite de '+total+' sabores atingido!');return;}
  if(newVal===0){delete miniFlavorCounts[flavor];}else{
    if(!miniFlavorCounts[flavor])miniFlavorCounts[flavor]={qty:0,shell:'Ao leite'};
    miniFlavorCounts[flavor].qty=newVal;
  }
  var spanId=flavorIdMap[flavor];
  if(spanId){var el=document.getElementById(spanId);if(el)el.textContent=newVal;}
  updateFlavorProgress();
}
function resetMiniFlavorSection(){
  miniFlavorCounts={};
  allFlavorIds.forEach(function(id){var el=document.getElementById(id);if(el)el.textContent='0';});
  Object.keys(flavorShellIdMap).forEach(function(flavor){
    var safeId=flavorShellIdMap[flavor];
    var lBtn=document.getElementById('mfs-'+safeId+'-l');
    var aBtn=document.getElementById('mfs-'+safeId+'-a');
    var bBtn=document.getElementById('mfs-'+safeId+'-b');
    if(lBtn){lBtn.style.background='var(--brown)';lBtn.style.borderColor='rgba(255,255,255,0.35)';lBtn.style.color='#fff';}
    if(aBtn){aBtn.style.background='transparent';aBtn.style.borderColor='rgba(255,255,255,0.25)';aBtn.style.color='rgba(255,255,255,0.7)';}
    if(bBtn){bBtn.style.background='transparent';bBtn.style.borderColor='rgba(255,255,255,0.25)';bBtn.style.color='rgba(255,255,255,0.7)';}
  });
  var section=document.getElementById('mini-flavor-section');
  if(section){section.style.display='none';}
  var btn=document.getElementById('mini-confirm-btn');
  if(btn)btn.style.display='none';
  updateFlavorProgress();
}
function changeMiniQty(cardId,delta){
  var opt=miniOptions[cardId];
  var el=document.getElementById(opt.qtyId);
  var val=parseInt(el.textContent)+delta;
  if(val<opt.minQty){showToast('Mínimo '+opt.minQty+' '+opt.unit+'!');return;}
  el.textContent=val;
  if(selectedMini===cardId)updateFlavorProgress();
}
function selectMini(id){
  if(selectedMini===id){
    document.getElementById(id).classList.remove('selected');
    selectedMini=null;
    resetMiniFlavorSection();
    var btn=document.getElementById('mini-confirm-btn');
    if(btn)btn.style.display='none';
    return;
  }
  document.querySelectorAll('.mini-card').forEach(function(c){c.classList.remove('selected');});
  document.getElementById(id).classList.add('selected');
  selectedMini=id;
  resetMiniFlavorSection();
  var btn=document.getElementById('mini-confirm-btn');
  if(btn){btn.style.display='block';setTimeout(function(){btn.scrollIntoView({behavior:'smooth',block:'nearest'});},50);}
}
function confirmMiniQty(){
  var section=document.getElementById('mini-flavor-section');
  if(section){section.style.display='flex';section.style.flexDirection='column';}
  setTimeout(function(){var top=section.getBoundingClientRect().top+window.pageYOffset-80;window.scrollTo({top:top,behavior:'smooth'});},50);
  updateFlavorProgress();
}
function addMini(){
  if(!selectedMini){showToast('Escolha uma opção!');return;}
  var total=getMiniTotalQty();
  var chosen=getMiniFlavorTotal();
  if(chosen===0){showToast('Escolha ao menos um sabor!');return;}
  if(chosen<total){showToast('Faltam '+(total-chosen)+' sabores!');return;}
  var opt=miniOptions[selectedMini];
  var qty=parseInt(document.getElementById(opt.qtyId).textContent);
  var flavorSummary=Object.entries(miniFlavorCounts).map(function(e){return e[1].qty+'× '+e[0]+' ('+e[1].shell+')';}).join(', ');
  cart.push({id:Date.now(),name:opt.name+' × '+qty,size:flavorSummary,price:opt.price*qty,type:'mini'});
  updateCartUI();
  showToast('✓ '+qty+' '+opt.name+' adicionado!');
  document.querySelectorAll('.mini-card').forEach(function(c){c.classList.remove('selected');});
  Object.values(miniOptions).forEach(function(o){document.getElementById(o.qtyId).textContent=o.minQty;});
  selectedMini=null;
  resetMiniFlavorSection();
  var confirmBtn=document.getElementById('mini-confirm-btn');
  if(confirmBtn)confirmBtn.style.display='none';
}document.addEventListener('DOMContentLoaded',function(){const popup=document.getElementById('live-popup');const countEl=document.getElementById('live-count');if(!popup||!countEl)return;const counts=[4,4,5,5,5,6,6,7];let lastCount=5;function getNewCount(){let next;do{next=counts[Math.floor(Math.random()*counts.length)];}while(next===lastCount);lastCount=next;return next;}function showPopup(){countEl.textContent=getNewCount();const cartOpen=document.getElementById('cart-modal')?.classList.contains('open');popup.style.bottom=cartOpen ? '420px':'90px';popup.classList.add('show');setTimeout(()=>popup.classList.remove('show'),4000);}setTimeout(()=>{showPopup();setInterval(showPopup,Math.floor(Math.random()*7000)+18000);},6000);});